            let task = task::create_task_from_elf_with_path(
                &elf_bytes,
                &argv_refs,
                &["PATH=/bin:/mnt:/mnt/musl:/mnt/glibc", "HOME=/", "TERM=dumb", "PWD=/"],
                "/bin/busybox",
