//! `Device` adapter, blocking helpers for the socket syscall layer.
//!
//! QEMU user-mode networking defaults:
//!   - guest IP : 10.0.2.15/24
//!   - gateway  : 10.0.2.2  (the host)
//!   - DNS      : 10.0.2.3

use alloc::sync::Arc;
