const EBADF: isize = -9;
const EFAULT: isize = -14;
const EINVAL: isize = -22;
const EISCONN: isize = -106;
const ENOTSOCK: isize = -88;
const EAFNOSUPPORT: isize = -97;
const EACCES: isize = -13;
const EPROTONOSUPPORT: isize = -93;
const ENETUNREACH: isize = -101;
const ECONNREFUSED: isize = -111;
const ECONNRESET: isize = -104;
const ENOTCONN: isize = -107;
const EAGAIN: isize = -11;
const EOPNOTSUPP: isize = -95;

/// True for 127.x.x.x or 0.0.0.0 — both of which the loopback shim should
/// service. (Most apps connect to 127.0.0.1 but a few bind to ANY and
/// reach themselves via localhost.)
fn is_loopback(a: Ipv4Address) -> bool {
    a.0[0] == 127 || a.0 == [0, 0, 0, 0]
}

/// Run `f` with a borrowed `&Socket` resolved from the fd table. Keeps the
/// `Arc<File>` alive for the duration of the call.
fn with_socket<R>(fd: i32, f: impl FnOnce(&Socket) -> R) -> Result<R, isize> {
    let task = current_task();
    let file = task.fd_table.lock().get(fd).ok_or(EBADF)?;
    let inode = file.inode.clone();
    if let Some(s) = inode.as_any().downcast_ref::<Socket>() {
        Ok(f(s))
    } else {
        Err(ENOTSOCK)
    }
}

/// Mark the current task Waiting and rewind sepc by 4 so the syscall
/// re-executes on wake-up. Caller's `dispatch()` will switch tasks via
/// `schedule_next_after_trap` because the state moved out of Running.
fn block_and_retry() {
    let me = current_task();
    if crate::syscall::nettrace_enabled() {
        let nr = unsafe { (*me.tf_ptr()).syscall_no() };
        crate::println!("[net] pid={} BLOCK on syscall#{}", me.pid, nr);
    }
    crate::task::mark_socket_waiter(me.pid);
    // Mark interruptible so a signal delivered while we're parked turns
    // this syscall into -EINTR (unless SA_RESTART) instead of silently
    // re-blocking after the handler returns.
    me.in_blocking_syscall.store(true, core::sync::atomic::Ordering::Relaxed);
    *me.state.lock() = crate::task::TaskState::Waiting;
    unsafe {
        let tf = me.tf_ptr();
        (*tf).rewind_syscall();
    }
}

/// Like `block_and_retry`, but re-evaluates `ready()` after switching to
/// Waiting. A peer that produces data between the caller's emptiness test
/// and our Waiting store calls `wake_socket_waiters()` while we are still
/// Running (a no-op), which would otherwise leave us parked forever. The
/// peer always mutates the shared queue *before* waking, so re-checking
/// here after the store closes that lost-wakeup window.
///
/// We also nudge other socket waiters *before* parking: in the iperf3 UDP
/// finalization the client blocks here waiting for the server's last
/// datagram while the server is parked in select; promoting the server to
/// Ready lets it run its loop and produce that datagram.
fn block_and_retry_recheck(ready: impl Fn() -> bool) {
    crate::task::wake_socket_waiters();
    block_and_retry();
    if ready() {
        let me = current_task();
        *me.state.lock() = crate::task::TaskState::Ready;
    }
}

/// Park the current task waiting for the loopback queue to fill, but no
/// longer than `timeout_ticks`. Returns `true` if the deadline has already
/// expired (caller should surface EAGAIN). Otherwise installs a sleep

//! System V IPC: shared memory, message queues, semaphores.
//!
//! LTP exercises the whole family (shmget/shmat/shmdt/shmctl, msgget/msgsnd/
//! msgrcv/msgctl, semget/semop/semctl/semtimedop) plus a pile of tests that
//! merely *set up* a SysV object as scaffolding; all of those previously
//! hard-failed because the syscalls returned -1/ENOSYS.
//!
//! Shared memory: the segment's pages are real frames owned by the global
//! table here and handed to each attaching address space as shared
//! `Arc<FrameTracker>`s, so a write through one attachment is visible through
//! every other — true shared memory, persisting past the creator's exit until
//! IPC_RMID + last detach, exactly like Linux.
//!
//! Message queues / semaphores: blocking msgrcv/msgsnd/semop use the same
//! park-and-retry shape as wait4/futex — mark the task Waiting, rewind the
//! ecall, and have the waking operation (msgsnd / semop increment / IPC_RMID)
//! flip the parked waiters back to Ready so the rewound syscall re-checks. No
//! lost wakeups: mid-syscall preemption is disabled, so check→park is atomic
//! w.r.t. other tasks.

use alloc::collections::BTreeMap;
use alloc::sync::Arc;
use alloc::vec::Vec;
use core::sync::atomic::{AtomicUsize, Ordering};

use crate::mm::frame::{alloc as alloc_frame, FrameTracker};
use crate::mm::memory_set::VmPerm;
use crate::sync::Mutex;

// ── errno values this module needs that syscall/mod.rs doesn't already pull in
const EINVAL: isize = -22;
const EFAULT: isize = -14;
const EACCES: isize = -13;
const ENOENT: isize = -2;
const EEXIST: isize = -17;
const ENOSPC: isize = -28;
const ENOMEM: isize = -12;

// ── ipc / shm command + flag constants (asm-generic, shared by rv64 & la64)
const IPC_PRIVATE: i32 = 0;
const IPC_CREAT: i32 = 0o1000;
const IPC_EXCL: i32 = 0o2000;
const IPC_RMID: i32 = 0;
const IPC_SET: i32 = 1;
const IPC_STAT: i32 = 2;
const IPC_INFO: i32 = 3;
const SHM_STAT: i32 = 13;
const SHM_INFO: i32 = 14;
const SHM_STAT_ANY: i32 = 15;
const SHM_RDONLY: i32 = 0o10000;
const SHM_RND: i32 = 0o20000;
/// Segment-attach boundary for SHM_RND. Page size is fine on both arches.
const SHMLBA: usize = PAGE_SIZE;

use crate::mm::address::PAGE_SIZE;

// ── tunables. Generous enough for every LTP case, bounded so a leaked/abusive
// segment can't eat the kernel the way unbounded tmpfs did.
const SHMMIN: usize = 1;
const SHMMAX: usize = 64 * 1024 * 1024;
const SHMMNI: usize = 4096;
/// Ceiling on the total frames pinned across all live segments (defense in
/// depth, same spirit as the tmpfs cap): a test that leaks segments can't pin
/// more than this. 128 MiB / 4 KiB pages.
const SHM_TOTAL_PAGES_MAX: usize = 128 * 1024 * 1024 / PAGE_SIZE;

static SHM_TOTAL_PAGES: AtomicUsize = AtomicUsize::new(0);

struct ShmSeg {
    shmid: i32,
    key: i32,
    size: usize,
    /// The segment's pages. Cloned (Arc) into each attaching address space.
    frames: Vec<Arc<FrameTracker>>,
    mode: u32,
    uid: u32,
    gid: u32,
    cuid: u32,
    cgid: u32,
    cpid: i32,

    // close-on-exec
    task.fd_table.lock().close_cloexec();

    // Record cmdline + exe_path for procfs. /proc/self/exe is read by
    // glibc's _dl_get_origin which assert()s the linkval starts with
    // '/'; resolve any relative path against the caller's cwd here so
    // the recorded exe_path is absolute. Without this the entire
    // glibc-dynamic test variant (lua-glibc, libctest-glibc, ...)
    // aborts on _dl_get_origin.
    *task.cmdline.lock() = build_cmdline(argv);
    if !exe_path.is_empty() {
        let s: String = exe_path.into();
        let abs = if s.starts_with('/') {
            s
        } else {
            let cwd = task.cwd.lock().clone();
            let cwd = cwd.trim_end_matches('/');
            let rel = s.strip_prefix("./").unwrap_or(&s);
            alloc::format!("{}/{}", cwd, rel)
        };
        *task.exe_path.lock() = abs;
    }
    // POSIX: keep mask, reset every user-installed handler to SIG_DFL
    // (SIG_IGN survives), clear pending, clear altstack.
    task.signals.reset_for_exec();
    // execve also clears any pending CLONE_CHILD_CLEARTID address.
    *task.clear_child_tid.lock() = 0;

    // CLONE_VFORK parent has been waiting for us to call execve. Now that
    // we have our own address space, the parent's stack is no longer at
    // risk of being trashed by us — let it resume.
    wake_vfork_parent_of(task.pid);

    Ok(())
}

/// First-time entry to user mode for the initial task.
pub fn run_user_loop(task: &Arc<Task>) -> ! {
    extern "C" {
        fn __trap_return(tf: *const TrapFrame) -> !;
    }

    let satp = task.memory_set.lock().satp();
    let tf_ptr = task.tf_ptr();

    crate::arch::activate_page_table(satp);
    unsafe {
        __trap_return(tf_ptr as *const _);
    }
}

/// Called by the trap handler. Decides which task to return through and
/// switches satp + current_pid accordingly. Returns the TF to load.
///
/// On loongarch64 this wraps the scheduler proper so the vector register
/// file (FP/LSX/LASX) follows the task switch. The kernel is soft-float and
/// leaves the file untouched, so when `pick_*` hands the CPU to a different
/// task we park the outgoing task's live registers and load the incoming
/// one's — without this, two vector workloads silently corrupt each other.
#[cfg(target_arch = "loongarch64")]
pub fn schedule_next_after_trap(current_tf: *mut TrapFrame) -> *mut TrapFrame {
    // The actual task change — and, on loongarch64, the FP/vector save+restore
    // that goes with it — now happens inside the inner scheduler via
    // `context_switch_to`, so this is a thin wrapper.
    schedule_next_after_trap_inner(current_tf)
}

#[cfg(not(target_arch = "loongarch64"))]
pub fn schedule_next_after_trap(current_tf: *mut TrapFrame) -> *mut TrapFrame {
    schedule_next_after_trap_inner(current_tf)
}

extern "C" {
    /// Restore a TrapFrame and return to its task's user mode (defined in
    /// trap.S). Used by the first-run trampoline.
    fn __trap_return(tf: *const TrapFrame) -> !;
}

/// First-run entry for a task that has never executed. The scheduler primes a
/// fresh task's kernel context (see [`Task::init_kctx_for_first_run`]) so the
/// first `__switch` into it lands here. CURRENT_PID is already this task, so
/// restore its user TrapFrame and enter user mode via the normal trap return.
extern "C" fn task_first_run() -> ! {
    let tf = current_task().tf_ptr();
    unsafe { __trap_return(tf) }
}

/// Park the currently-running task (`prev_pid`) and resume `next_pid` by
/// switching kernel contexts. `next_pid` must already be published as
/// CURRENT_PID, with its page table active and its pending signals delivered.
/// `prev_tf` is the trap frame to resume `prev_pid` through when it next runs
/// — its user TrapFrame at a trap-exit boundary, or the nested timer frame if
/// `prev_pid` is being preempted mid-syscall. It is returned (on `prev_pid`'s
/// timeline) once `prev_pid` is scheduled again, so the trap handler sret's to
/// the right place (back to user, or back into the interrupted syscall).
///
/// # Safety
/// Call only from the scheduler at a point where no kernel lock is held; both
/// pids must name live tasks with intact kernel stacks.
unsafe fn context_switch_to(
    prev_pid: i32,
    next_pid: i32,
    prev_tf: *mut TrapFrame,
) -> *mut TrapFrame {
    let prev_kctx = task_by_pid(prev_pid).map(|t| t.kctx_ptr());
    let next_kctx = task_by_pid(next_pid).map(|t| t.kctx_ptr());
    if let (Some(p), Some(n)) = (prev_kctx, next_kctx) {
        // loongarch64: the kernel is soft-float, so the outgoing task's live
        // FP/LSX/LASX state lives only in the hardware regs until parked. Save
        // it and load the incoming task's before the GPR switch.
        #[cfg(target_arch = "loongarch64")]
        {
            if let Some(prev) = task_by_pid(prev_pid) {
                unsafe { crate::arch::loongarch64::fpu::save(prev.fp_ptr()) };
            }
            if let Some(next) = task_by_pid(next_pid) {
                unsafe { crate::arch::loongarch64::fpu::restore(next.fp_ptr()) };
            }
        }
        unsafe { crate::arch::switch_context(p, n) };
    }
    // Resumed: continue `prev_pid` through the frame it parked on.
    prev_tf
}

fn schedule_next_after_trap_inner(current_tf: *mut TrapFrame) -> *mut TrapFrame {
    // Push/pull whatever the network stack has been doing while user-mode
    // ran. Only wake socket-blocked tasks if poll actually made progress;
    // otherwise the same task (e.g. iperf3 -s on accept) re-Ready'd itself
    // every trap and starved every other scheduler candidate, including
