//! Physical frame allocator.
//!
//! Wraps `buddy_system_allocator::FrameAllocator` so callers see a typed
//! `PhysPageNum`. `FrameTracker` is an RAII guard that frees on drop —
//! exactly what `MemorySet` wants when a process exits.

use core::fmt;
use core::sync::atomic::{AtomicUsize, Ordering};

use buddy_system_allocator::LockedFrameAllocator;
use spin::Lazy;

use super::address::{PhysAddr, PhysPageNum, PAGE_SIZE};

static FRAME_ALLOC: Lazy<LockedFrameAllocator<32>> = Lazy::new(LockedFrameAllocator::new);

/// Total pages put into the frame pool at boot (constant after `init`).
static TOTAL_PAGES: AtomicUsize = AtomicUsize::new(0);
/// Pages currently handed out (in-use). Decremented on dealloc.
static ALLOCATED_PAGES: AtomicUsize = AtomicUsize::new(0);


/// Register the [start, end) physical range as the kernel's free frame pool.
/// Pass `[__kernel_end .. MEMORY_END)` from boot.
pub fn init(pa_start: PhysAddr, pa_end: PhysAddr) {
    let start = pa_start.0.div_ceil(PAGE_SIZE);
    let end = pa_end.0 / PAGE_SIZE;
    assert!(end > start, "frame range empty");
    FRAME_ALLOC.lock().add_frame(start, end);
    TOTAL_PAGES.store(end - start, Ordering::Relaxed);
}

/// Pool an ADDITIONAL physical `[start, end)` bank after `init`. The buddy
/// allocator already supports disjoint banks (`add_frame` may be called more
/// than once), so this just folds a second region into the free pool and grows
/// the page total. Used on boards whose RAM is split across banks — notably the
/// loongarch64 QEMU `virt` machine, whose low bank at PA 0 is separate from the
/// high bank the kernel loads into and was otherwise left unused (the ~256 MiB
/// that decides whether the LA contest run completes or OOM-wedges mid-glibc).
pub fn add_region(pa_start: PhysAddr, pa_end: PhysAddr) {
    let start = pa_start.0.div_ceil(PAGE_SIZE);
    let end = pa_end.0 / PAGE_SIZE;
    if end <= start {
        return;
    }
    FRAME_ALLOC.lock().add_frame(start, end);
    TOTAL_PAGES.fetch_add(end - start, Ordering::Relaxed);
}

/// Force-release the frame pool's internal spinlock — the physical-memory twin
/// of [`crate::mm::heap::force_unlock`]. A wedged/faulted stack abandoned inside
/// `try_alloc_zeroed`/`dealloc` would otherwise strand this lock and hang every
/// later page-fault, fork and execve (all of which take a frame) — cascading a
/// single bad case into a dead run. Called from the fault/watchdog recovery.
///
/// # Safety
/// Single-hart fault/watchdog recovery only; the abandoned stack is then the
/// only possible holder.
pub unsafe fn force_unlock() {
    unsafe { FRAME_ALLOC.force_unlock() };
}

pub fn alloc() -> Option<FrameTracker> {
    if let Some(f) = try_alloc_zeroed() {
        return Some(f);
    }
    // Out of frames: reclaim a finished fork/thread-storm's dead leftovers
    // (their user frames are freed as the tasks are reaped) and retry once.
    crate::task::emergency_reclaim();
    try_alloc_zeroed()
}

fn try_alloc_zeroed() -> Option<FrameTracker> {
    // The frame pool is guarded by a plain spin::Mutex (inside
    // LockedFrameAllocator) that the preemption count can't see; disable
    // preemption around it so a preempted holder can't deadlock the next
    // allocator on this single hart.
    crate::sync::preempt_disable();
    let res = FRAME_ALLOC
        .lock()
        .alloc(1)
        .map(|ppn_usize| FrameTracker::new_zeroed(PhysPageNum(ppn_usize)));
    crate::sync::preempt_enable();
    if res.is_some() {
        ALLOCATED_PAGES.fetch_add(1, Ordering::Relaxed);
    }
    res
}

/// Allocate a frame WITHOUT zeroing it. Only sound when the caller
/// immediately overwrites the entire page; otherwise stale physical
/// contents would leak to user space. The fork copy path qualifies — it
/// does a full-page `copy_from_slice` straight after — and skipping the
/// zero there removes a redundant 4 KiB write per copied page (the page is
/// zeroed and then overwritten), which matters when a busybox `fork`
/// duplicates a multi-thousand-page address space on every shell command.
pub fn alloc_uninit() -> Option<FrameTracker> {
    if let Some(f) = try_alloc_uninit() {
        return Some(f);
    }
    crate::task::emergency_reclaim();
    try_alloc_uninit()
}

fn try_alloc_uninit() -> Option<FrameTracker> {
    crate::sync::preempt_disable();
    let res = FRAME_ALLOC
        .lock()
        .alloc(1)
        .map(|ppn_usize| FrameTracker { ppn: PhysPageNum(ppn_usize) });
    crate::sync::preempt_enable();
    if res.is_some() {
        ALLOCATED_PAGES.fetch_add(1, Ordering::Relaxed);
    }
    res
}

pub fn dealloc(ppn: PhysPageNum) {
    crate::sync::preempt_disable();
    FRAME_ALLOC.lock().dealloc(ppn.0, 1);
    crate::sync::preempt_enable();
    ALLOCATED_PAGES.fetch_sub(1, Ordering::Relaxed);
}

/// (total_pages, free_pages) snapshot of the frame allocator. Used by procfs
/// to fill in /proc/meminfo.
pub fn frame_stats() -> (usize, usize) {
    let total = TOTAL_PAGES.load(Ordering::Relaxed);
    let used = ALLOCATED_PAGES.load(Ordering::Relaxed);
    (total, total.saturating_sub(used))
}

/// Owns one physical frame; frees on drop.
pub struct FrameTracker {
    pub ppn: PhysPageNum,
}

impl FrameTracker {
    fn new_zeroed(ppn: PhysPageNum) -> Self {
        for b in ppn.as_byte_slice().iter_mut() {
            *b = 0;
        }
        Self { ppn }
    }
}

impl Drop for FrameTracker {
    fn drop(&mut self) {
        dealloc(self.ppn);
    }
}

impl fmt::Debug for FrameTracker {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "FrameTracker({:?})", self.ppn)
    }
}

//! Kernel heap.
//!
//! Lives in a static `.bss` buffer; the buddy allocator manages it as a
//! linked free list. M1 keeps this simple — once frame allocation is up
//! we could move to a slab on top, but a single LockedHeap covers all
//! kmalloc needs through M5 easily.

use buddy_system_allocator::LockedHeap;
use core::alloc::{GlobalAlloc, Layout};

/// Preempt-safe global allocator. The buddy `LockedHeap` guards its free lists
/// with a plain `spin::Mutex` that the preemption count cannot see, so a task
/// preempted mid-allocation would strand that lock and deadlock the next task's
/// allocation on this single hart. Bracket every alloc/dealloc with
/// preempt_disable/enable so the scheduler never switches away while the heap
/// lock is held. (realloc/alloc_zeroed use the default impls, which route
/// through these.)
struct PreemptHeap(LockedHeap<32>);

unsafe impl GlobalAlloc for PreemptHeap {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        crate::sync::preempt_disable();
        let p = self.0.alloc(layout);
        crate::sync::preempt_enable();
        p
    }
    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        crate::sync::preempt_disable();
        self.0.dealloc(ptr, layout);
        crate::sync::preempt_enable();
    }
}

// libc-bench's b_stdio_putcgetc et al. allocate ~8 MB scratch buffers
// per bench. The contest harness also forks many short-lived ELFs whose
// images we slurp into Vec<u8> in sys_execve. 32 MB was hitting alloc
// failures mid-libcbench. 128 MB still fits inside QEMU virt's -m 1G.
const KERNEL_HEAP_SIZE: usize = 256 * 1024 * 1024;

#[link_section = ".bss.heap"]
static mut KERNEL_HEAP: [u8; KERNEL_HEAP_SIZE] = [0; KERNEL_HEAP_SIZE];

#[global_allocator]
static HEAP_ALLOCATOR: PreemptHeap = PreemptHeap(LockedHeap::empty());

pub fn init() {
    unsafe {
        HEAP_ALLOCATOR
            .0
            .lock()
            .init(KERNEL_HEAP.as_mut_ptr() as usize, KERNEL_HEAP_SIZE);
    }
}

/// Force-release the buddy heap's internal spinlock. The preempt_disable bracket
/// in alloc/dealloc keeps the scheduler from switching mid-allocation, but it
/// can't help the watchdog/fault recovery path, which *abandons* the wedged
/// stack without unwinding. If that stack was inside `alloc` (an LTP case that
/// loops allocating until the 8 s watchdog fires is frequently mid-alloc when
/// the timer lands), the heap lock stays held forever and EVERY later
/// allocation — including pid 1's — spins, cascading the whole run to death.
/// `force_release_locks_after_fault` calls this so a single wedged case can't
/// strand the allocator.
///
/// # Safety
/// Call only from the single-hart fault/watchdog recovery, where the abandoned
/// stack is the only possible holder of the lock.
pub unsafe fn force_unlock() {
    unsafe { HEAP_ALLOCATOR.0.force_unlock() };
}

