//! In-kernel symbol resolution ("ksyms"). A post-link build step embeds a
//! compact `{sorted addrs, names}` blob (see `scripts/gen_ksyms.py`) so the
//! kernel can turn a fault/panic PC into `function+offset` *by itself* —
//! crucial for the contest, where the grader's rustc (and thus .text layout)
//! may differ from any local build, so a bare `era=0x...` won't addr2line.
//!
//! Fail-safe: if the blob is absent/empty (the placeholder a normal one-pass
//! build embeds), every lookup just returns `None` and callers fall back to
//! printing the raw address — exactly the pre-ksyms behaviour. So a failed or
//! skipped symbol-generation step can never break the build or the kernel.

/// The embedded blob. `build.rs` points `KSYMS_BIN_PATH` at the generated file
/// (or an empty placeholder). Layout (all little-endian):
///   u32 magic=0x4B53594D, u32 count,
///   u64 addr[count] (ascending), u32 name_off[count],
///   u32 strtab_len, u8 strtab[strtab_len] (NUL-terminated names).
static BLOB: &[u8] = include_bytes!(env!("KSYMS_BIN_PATH"));

/// Fetch the blob through an optimisation barrier. CRITICAL for the two-pass
/// embed: pass 1 links with an EMPTY placeholder blob. If the optimiser could
/// see that (a known-empty const), it would prove `table()` returns None,
/// const-fold `available()`/`resolve()` to nothing, and dead-code-eliminate
/// every `if ksyms::available()` block — shrinking `.text`. Pass 2 (real,
/// non-empty blob) keeps that code, so `.text` would be LARGER and every
/// address the pass-1 blob recorded would be wrong (observed: kmain off by
/// 0x2a0). `black_box` makes the blob's content AND length opaque, so both
/// passes generate byte-identical code and the recorded addresses stay valid.
#[inline(never)]
fn blob() -> &'static [u8] {
    // Load the slice (data pointer AND length) from BLOB's address at runtime,
    // through an opaque pointer, so neither field is materialized as a
    // value-dependent immediate. `black_box(BLOB)` alone still let the length
    // (0 in pass 1 vs the real size in pass 2) be const-loaded, which shifted
    // this function's code — and thus every later .text address — by a few
    // bytes. Reading the fat pointer from memory makes both passes byte-identical.
    unsafe { *core::hint::black_box(core::ptr::addr_of!(BLOB)) }
}

const MAGIC: u32 = 0x4B53_594D;

#[inline]
fn rd_u32(b: &[u8], o: usize) -> Option<u32> {
    Some(u32::from_le_bytes(b.get(o..o + 4)?.try_into().ok()?))
}
#[inline]
fn rd_u64(b: &[u8], o: usize) -> Option<u64> {
    Some(u64::from_le_bytes(b.get(o..o + 8)?.try_into().ok()?))
}

struct Table {
    count: usize,
    addrs_off: usize,   // u64[count]
    names_off: usize,   // u32[count]
    strtab_off: usize,
    strtab_len: usize,
}

fn table() -> Option<Table> {
    let b = blob();
    if rd_u32(b, 0)? != MAGIC {
        return None;
    }
    let count = rd_u32(b, 4)? as usize;
    if count == 0 {
        return None;
    }
    let addrs_off = 8;
    let names_off = addrs_off + count * 8;
    let strtab_len_off = names_off + count * 4;
    let strtab_len = rd_u32(b, strtab_len_off)? as usize;
    let strtab_off = strtab_len_off + 4;
    // Bounds-check the whole blob so a truncated one degrades to None.
    if strtab_off.checked_add(strtab_len)? > b.len() {
        return None;
    }
    Some(Table { count, addrs_off, names_off, strtab_off, strtab_len })
}

/// Resolve `addr` to the nearest enclosing function symbol, returning its name
/// and the byte offset of `addr` from the symbol's start.
pub fn resolve(addr: usize) -> Option<(&'static str, usize)> {
    let t = table()?;
    let b = blob();
    let addr = addr as u64;
    let at = |i: usize| rd_u64(b, t.addrs_off + i * 8).unwrap_or(u64::MAX);
    if addr < at(0) {
        return None;
    }
    // Largest index whose addr <= query.
    let (mut lo, mut hi) = (0usize, t.count - 1);
    while lo < hi {
        let mid = (lo + hi + 1) / 2;
        if at(mid) <= addr {
            lo = mid;
        } else {
            hi = mid - 1;
        }
    }
    let base = at(lo);
    let name_off = rd_u32(b, t.names_off + lo * 4)? as usize;
    let s = t.strtab_off + name_off;
    let strtab = b.get(t.strtab_off..t.strtab_off + t.strtab_len)?;
    let rel = name_off;
    let end = strtab.get(rel..)?.iter().position(|&c| c == 0)? + rel;
    let name = core::str::from_utf8(b.get(s..t.strtab_off + end)?).ok()?;
    Some((name, (addr - base) as usize))
}

/// True if a real symbol table is embedded (i.e. not the empty placeholder).
pub fn available() -> bool {
    table().is_some()
}

/// Print `  <addr>  <name>+<off>` (or just the address if unresolved). Used by
/// the panic/fault paths to annotate a PC or return address.
pub fn print_frame(label: &str, addr: usize) {
    match resolve(addr) {
        Some((name, off)) => crate::println!("  {label} {addr:#018x}  {name}+{off:#x}"),
        None => crate::println!("  {label} {addr:#018x}  ??"),
    }
}

//! Anonymous pipes (M5).
//!
//! Each pipe has a fixed-size ring buffer and two `Inode` ends.

use alloc::collections::VecDeque;
use alloc::sync::Arc;
use core::any::Any;
use crate::sync::Mutex;

use super::{FileType, Inode, Result, EBADF, EINVAL};

const EPIPE: i32 = -32;

pub const PIPE_CAP: usize = 64 * 1024;

struct PipeBuffer {
    buf: VecDeque<u8>,
    closed_read: bool,
    closed_write: bool,
    /// pids of tasks parked in sys_read on the read end, waiting for
    /// data to arrive (or the writer to close). Woken by the writer's
    /// write_at and by Drop on the writer end.
    read_waiters: alloc::vec::Vec<i32>,
    /// Capacity (in bytes) reported by fcntl(F_GETPIPE_SZ) and the high-water
    /// mark a writer may buffer. fcntl(F_SETPIPE_SZ) adjusts it.
    capacity: usize,
    /// Async-I/O target for fcntl(F_SETFL,O_ASYNC)+F_SETOWN+F_SETSIG, mirrored
    /// here from the read end's `File` so a writer can signal data readiness.
    /// `owner`: pid (>0) / negated pgid (<0); `signal`: 0 = default SIGIO.
    async_owner: i32,
    async_signal: i32,
    async_armed: bool,
}

pub struct PipeEnd {
    inner: Arc<Mutex<PipeBuffer>>,
    is_writer: bool,
}

impl PipeEnd {
    pub fn is_writer(&self) -> bool { self.is_writer }
    pub fn writer_alive(&self) -> bool {
        let p = self.inner.lock();
        !p.closed_write
    }
    pub fn buffered(&self) -> usize {
        self.inner.lock().buf.len()
    }
    /// Copy up to `max` buffered bytes WITHOUT consuming them — tee(2)
    /// duplicates a pipe's data into another pipe, leaving the source readable.
    pub fn peek(&self, max: usize) -> alloc::vec::Vec<u8> {
        let pipe = self.inner.lock();
        let n = core::cmp::min(max, pipe.buf.len());
        pipe.buf.iter().take(n).copied().collect()
    }
    /// Current pipe capacity in bytes (fcntl F_GETPIPE_SZ).
    pub fn capacity(&self) -> usize {
        self.inner.lock().capacity
    }
    /// Set the pipe capacity in bytes (fcntl F_SETPIPE_SZ, already validated).
    pub fn set_capacity(&self, cap: usize) {
        self.inner.lock().capacity = cap;
    }
    /// Mirror the read end's async-I/O settings into the shared buffer so the
    /// peer writer can raise the configured signal when data arrives.
    pub fn set_async(&self, owner: i32, signal: i32, armed: bool) {
        let mut p = self.inner.lock();
        p.async_owner = owner;
        p.async_signal = signal;
        p.async_armed = armed;
    }
    pub fn add_read_waiter(&self, pid: i32) {
        let mut p = self.inner.lock();
        if !p.read_waiters.contains(&pid) {
            p.read_waiters.push(pid);
        }
    }

    /// Atomically decide whether to block a reader, and if so register it and
    /// park it — all under ONE pipe lock. Returns true if the pipe was empty
    /// with a live writer (the caller should rewind the syscall and yield);
    /// false if data is available or the writer is gone (caller re-reads / gets
    /// EOF).
    ///
    /// This closes a lost-wakeup race that the previous split sequence
    /// (`buffered()==0`, then a separate `add_read_waiter()`, then a separate
    /// `state = Waiting`) left open: a `write_at` landing between the empty
    /// check and the registration pushed data and `mem::take`'d an empty waiter
    /// list, waking nobody, so the reader then registered and slept forever.
    /// lmbench's `lat_pipe` (a tight 2-process pipe ping-pong) hit that window
    /// on nearly every exchange, deadlocking both ends — which left the whole
    /// lmbench group without an END marker and scored it 0. Holding the lock
    /// across the empty check, the registration, AND the Waiting transition
    /// means a concurrent `write_at` either runs before us (we observe the data
    /// and return false) or after us (it observes our registered, Waiting
    /// reader and wakes it).
    pub fn block_reader_if_empty(&self, task: &Arc<crate::task::Task>) -> bool {
        if self.is_writer {
            return false;
        }
        let mut p = self.inner.lock();
        if !p.buf.is_empty() || p.closed_write {
            return false; // data to read, or writer gone (EOF) — don't block
        }
        if !p.read_waiters.contains(&task.pid) {
            p.read_waiters.push(task.pid);
        }
        *task.state.lock() = crate::task::TaskState::Waiting;
        true
    }
}

/// Deliver the async-I/O signal to a fcntl(F_SETOWN) target: a pid when
/// `owner > 0`, or every member of process group `-owner` when `owner < 0`.
/// `signal == 0` selects the POSIX default, SIGIO.
fn deliver_io_signal(owner: i32, signal: i32) {
    let signo = if signal == 0 {
        crate::signal::SIGIO
    } else {
        signal as u32
    };
    if owner > 0 {
        if let Some(t) = crate::task::task_by_pid(owner) {
            crate::signal::raise_signal(&t, signo);
        }
    } else if owner < 0 {
        let pgid = -owner;
        for pid in crate::task::all_pids() {
            if let Some(t) = crate::task::task_by_pid(pid) {
                if t.pgid.load(core::sync::atomic::Ordering::Relaxed) == pgid {
                    crate::signal::raise_signal(&t, signo);
                }
            }
        }
    }
}

fn wake_pipe_readers(waiters: &[i32]) {
    for &pid in waiters {
        if let Some(t) = crate::task::task_by_pid(pid) {
            let mut s = t.state.lock();
            if *s == crate::task::TaskState::Waiting {
                *s = crate::task::TaskState::Ready;
            }
        }
    }
}

