}

impl FatFile {
    fn data(&self) -> Vec<u8> {
        let mut c = self.cached.lock();
        if let Some(d) = &*c {
            return d.clone();
        }
        let blob = self
            .fs
            .read_cluster_chain(self.first_cluster, Some(self.size as usize));
        *c = Some(blob.clone());
        blob
    }
}

